require.config({
  paths: {
    pageRelation: "$xwiki.getDocument('OpenProject.Code.PageRelationLoadJSX').getURL('jsx', 'r=1')"
  }
});
require(['deferred!ckeditor', 'jquery', 'pageRelation'], function (ckeditorPromise, $, pageRelation) {
  const search = function (text, callback, instance) {
    let cfg = { query: { filters: [{ property: "summary", constraints: [{ operator: "contains", value: text }] }] } };
    $.getJSON('/xwiki/rest/wikis/xwiki/projectmanagement/openproject/workitems', { instance: instance, filter: JSON.stringify(cfg)})
      .then(function (results) {
        if (Array.isArray(results.items)) {
          results = results.items.map(wp => {
            return { id: wp.identifier.value, value: wp.identifier.value, label: wp.summary.value, typebadge: wp.type, projectbadge: wp.project.value, instance: instance };
          });
          callback(results);
          return;
        } else {
          callback([]);
        }
      })
      .catch(function (e) {
        console.log(`error trying to retrieve selectize searchUrl ${searchURL} elements.` + e);
        callback([]);
      });
  };
  ckeditorPromise.then(ckeditor => {
    function getOpenProjectPluginCfg(editor) {
      return {
        dataCallback: function (options, callback) {
          // Remove the marker prefix and replace non-breaking space.
          const text = options.query.substring(1).replaceAll('\u00A0', ' ');
          pageRelation.get().done(function (relation) {
            if (!relation || !relation.clientParams || !relation.clientParams.instance) {
              console.warn('There is no instance stored in the page relation.');
              return;
            }
            search(text, callback, relation.clientParams.instance);
          });
        },
        marker: '#',
        minChars: 3,
        itemsLimit: 10,
        itemTemplate:
          `<li data-id="{id}" class="ckeditor-autocomplete-item">
            <div class="ckeditor-autocomplete-item-head">
              <span class="ckeditor-autocomplete-item-label">{label}</span>
            </div>
            <div class="ckeditor-autocomplete-item-badges">
              <span class="badge ckeditor-autocomplete-item-badge">{typebadge}</span>
              <span class="badge ckeditor-autocomplete-item-badge">{projectbadge}</span>
            </div>
          </li>`,
        outputTemplate: function (param) {
          editor.once('afterInsertHtml', function () {
            editor.execCommand('xwiki-macro-insert', {
              name: 'openproject',
              inline: "enforce",
              parameters: {
                instance: param.instance,
                identifier: param.id,
                workItemsDisplayer: "workItemInline"
              }
            });
          });
          // the outputTemplate insert nothing but wait for the afterInsertHtml event to be triggered
          // at this point the xwiki-macro-insert deals with the macro insertion in the rich editor.
          return '';
        }
      };
    }

    // Enable the plugin for the CKEditor instances that have been already created.
    Object.values(ckeditor.instances).forEach(maybeEnableOpenProjectPlugin);
    // Enable the plugin for the CKEditor instances that are going to be created from now on.
    ckeditor.on('instanceCreated', (event) => {
      maybeEnableOpenProjectPlugin(event.editor);
    });

    function maybeEnableOpenProjectPlugin(editor) {
      return waitForEditorReady(editor).then(editor => {
        new CKEDITOR.plugins.AdvancedAutoComplete(editor, getOpenProjectPluginCfg(editor));
        return editor;
      });
    }

    function waitForEditorReady(editor) {
      return new Promise((resolve, reject) => {
        if (editor.status === 'ready') {
          resolve(editor);
        } else {
          editor.once('instanceReady', (event) => {
            resolve(event.editor);
          });
        }
      });
    }
  });
});
